param([string]$BaseUrl='http://localhost:18081',[string]$BackendUrl='http://localhost:18080',[string]$OutputDirectory,[switch]$SkipApplicationStart,[switch]$KeepApplicationRunning,[switch]$Headed)
Set-StrictMode -Version Latest;$ErrorActionPreference='Stop'
$repo=[IO.Path]::GetFullPath((Join-Path $PSScriptRoot '..\..'));if(!$OutputDirectory){$OutputDirectory=Join-Path $repo 'artifacts\manual'}
$steps=@('Preflight-Manual.ps1','Start-Gestudio.ps1','Seed-ManualDemo.ps1','Capture-Manual.ps1','Render-Manual.ps1','Validate-Manual.ps1');foreach($s in $steps){if(!(Test-Path (Join-Path $PSScriptRoot $s))){throw "Falta script auxiliar: $s"}}
New-Item -ItemType Directory -Force $OutputDirectory|Out-Null;$started=$false
try{& (Join-Path $PSScriptRoot 'Preflight-Manual.ps1') -BaseUrl $BaseUrl -BackendUrl $BackendUrl;if($LASTEXITCODE-ne 0){throw 'Falló Preflight.'};if(!$SkipApplicationStart){$r=& (Join-Path $PSScriptRoot 'Start-Gestudio.ps1') -BaseUrl $BaseUrl -BackendUrl $BackendUrl;$started=$r -contains 'APPLICATION_STARTED_BY_GENERATOR=true'};& (Join-Path $PSScriptRoot 'Seed-ManualDemo.ps1') -BackendUrl $BackendUrl;if($LASTEXITCODE-ne 0){throw 'Falló la validación demo.'};& (Join-Path $PSScriptRoot 'Capture-Manual.ps1') -BaseUrl $BaseUrl -OutputDirectory $OutputDirectory -Headed:$Headed;if($LASTEXITCODE-ne 0){throw 'Falló la captura.'};& (Join-Path $PSScriptRoot 'Render-Manual.ps1') -BaseUrl $BaseUrl -BackendUrl $BackendUrl -OutputDirectory $OutputDirectory -ApplicationStartedByGenerator:$started;if($LASTEXITCODE-ne 0){throw 'Falló el render.'};& (Join-Path $PSScriptRoot 'Validate-Manual.ps1') -OutputDirectory $OutputDirectory;if($LASTEXITCODE-ne 0){throw 'Falló la validación.'};Write-Host "PDF: $(Join-Path $OutputDirectory 'Manual_Gestudio_Usuarios_Nuevos.pdf')"}finally{if($started-and!$KeepApplicationRunning){& (Join-Path $repo 'scripts\demo-local.ps1') -Action Stop}}